function [peakA,threL,meanA,stdA] = fSttClmnV01(img,varargin)%% Statistics on each column of the input image,% return peak, threshold logic, mean and standard deviation for each column%% [peakA,threA,meanA,stdA] = fSttClmnV01(img,varargin)%% img: input image (M x N)% varargin{1}: y: y axis (1 x M array), optional, default axis is index% varargin{2}: threV: threshold value (1 x N array), threshold for each column%% peakA: (1 x N) array, peak row (y)% threL: (1 x N) array of logic, >threIn% meanA: (1 x N) array, mean of each column for input image% stdA: (1 x N) array, standard deviation of each column for input image%% written by Kei Nakamura% ver.1: 2012/7/19 Thursday% created.%% main body% figure(7)% pcolor(log10(img)); shading interp; colorbar;%% input parameters[szY,szX] = size(img);  % size of the input imageif nargin==1            % only img is given for input    y = [1:szY];    threV = zeros(1,szX);elseif nargin==2        % img and y are given    y = varargin{1};    threV = zeros(1,szX);else                    % img, y and threV are given, but y can be empty    if isempty(varargin{1})        y = [1:szY];    else        y = varargin{1};    end    threV = varargin{2};end%% peak and threshold logic[peakV,peakI] = max(img);   % peak value and peak indexpeakA = y(peakI);           % peak y for each columnthreL = peakV>threV;        % threhold logic%% mean and standard deviation[~,yGrid] = meshgrid(1:szX,y);meanA = sum(yGrid.*img)./sum(img);  % mean angle for each column[meanGrid,~] = meshgrid(meanA,y);   % mean angle gridmeanGrid = abs(yGrid-meanGrid); % distance from mean gridstdA = sum(meanGrid.*img)./sum(img);    % standard dev for each column%% convert nan to 0.nanI = isnan(meanA);meanA(nanI) = 0;stdA(nanI) = 0;
